  1→import { useFocusEffect } from '@react-navigation/native';
  2→import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  3→import type { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
  4→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  5→import {
  6→  InteractionManager,
  7→  NativeScrollEvent,
  8→  NativeSyntheticEvent,
  9→} from 'react-native';
 10→import { useShallow } from 'zustand/react/shallow';
 11→import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
 12→import { useRootStore } from '~/store';
 13→import useDebounce from '../../hooks/useDebounce';
 14→import {
 15→  getPointsBalance,
 16→  getPointsExtract,
 17→  PERIOD_DAYS_MAP,
 18→  PointsBalanceStatus,
 19→  PointsExtractStatus,
 20→  processPointsExtractData,
 21→  type AppliedFilters,
 22→  type PointsTransaction,
 23→} from '../../services';
 24→import { EXTRACT_CONSTANTS } from '../../services/constants';
 25→import { ANALYTICS_EVENTS, SCREEN_STRINGS } from './data';
 26→import type {
 27→  ExtractRewardProgramProps,
 28→  FilterGroup,
 29→  UseExtractRewardProgramReturn,
 30→} from './Models';
 31→
 32→import {
 33→  getFilteredTransactions,
 34→  getFilteredTransactionsByText,
 35→} from './utils';
 36→
 37→const SCROLL_THRESHOLD = 300;
 38→
 39→export function useExtractRewardProgramScreen(
 40→  params?: ExtractRewardProgramProps,
 41→): UseExtractRewardProgramReturn {
 42→  const hasTrackedScreenView = useRef(false);
 43→  const hasTrackedSearchPress = useRef(false);
 44→  const canLoadMoreRef = useRef(false);
 45→  const isLoadingMoreRef = useRef(false);
 46→
 47→  const modalizeRefInfo = useRef<PropsModalizeRef>(
 48→    null as unknown as PropsModalizeRef,
 49→  );
 50→  const modalizeRefFilters = useRef<PropsModalizeRef>(
 51→    null as unknown as PropsModalizeRef,
 52→  );
 53→
 54→  const [isRefreshing, setIsRefreshing] = useState(false);
 55→  const [transactionsData, setTransactionsData] = useState<
 56→    propsItemsListCardTransition[]
 57→  >([]);
 58→  const [searchText, setSearchText, debouncedSearchText] = useDebounce('', 400);
 59→
 60→  const {
 61→    pointsExtract,
 62→    pointsBalance,
 63→    pointsExtractFilters,
 64→    pointsExtractActions,
 65→  } = useRootStore(
 66→    useShallow(state => ({
 67→      pointsExtract: state.pointsExtract,
 68→      pointsBalance: state.pointsBalance,
 69→      pointsExtractFilters: state.pointsExtractFilters,
 70→      pointsExtractActions: state.pointsExtractActions,
 71→    })),
 72→  );
 73→
 74→  const isLoadingExtract = pointsExtract.status === PointsExtractStatus.LOADING;
 75→  const isLoadingMore = pointsExtract.isLoadingMore;
 76→  const isLoadingBalance = pointsBalance.status === PointsBalanceStatus.LOADING;
 77→  const appliedTransactionsFilters =
 78→    pointsExtractFilters.appliedTransactionsFilters;
 79→  const hasError =
 80→    pointsExtract.status === PointsExtractStatus.ERROR &&
 81→    !isLoadingExtract &&
 82→    (!pointsExtract.extractData ||
 83→      !pointsExtract.extractData.transactions?.length);
 84→
 85→  useFocusEffect(
 86→    useCallback(() => {
 87→      if (!hasTrackedScreenView.current) {
 88→        eventScreenViewV3(
 89→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_name,
 90→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_class,
 91→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_bussines,
 92→          {
 93→            location_1: ANALYTICS_EVENTS.SCREEN_VIEW.location_1,
 94→            location_2: ANALYTICS_EVENTS.SCREEN_VIEW.location_2,
 95→            location_3: ANALYTICS_EVENTS.SCREEN_VIEW.location_3,
 96→          },
 97→        );
 98→        hasTrackedScreenView.current = true;
 99→      }
100→
101→      return () => {
102→        hasTrackedScreenView.current = false;
103→      };
104→    }, []),
105→  );
106→
107→  const refreshExtractData = useCallback(() => {
108→    pointsExtractActions.setExtractStatus(PointsExtractStatus.IDLE);
109→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
110→    pointsExtractActions.setLoadingMore(false);
111→    getPointsBalance();
112→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
113→  }, [pointsExtractActions]);
114→
115→  useFocusEffect(
116→    useCallback(() => {
117→      refreshExtractData();
118→    }, [refreshExtractData]),
119→  );
120→
121→  useEffect(() => {
122→    const shouldFetchBalance =
123→      pointsBalance.points === undefined ||
124→      pointsBalance.status === PointsBalanceStatus.ERROR;
125→
126→    if (shouldFetchBalance) {
127→      getPointsBalance();
128→    }
129→
130→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
131→  }, [
132→    pointsBalance.points,
133→    pointsBalance.status,
134→  ]);
135→
136→  useEffect(() => {
137→    if (!isLoadingExtract && isRefreshing) {
138→      setIsRefreshing(false);
139→    }
140→  }, [
141→    isLoadingExtract,
142→    isRefreshing,
143→  ]);
144→
145→  useEffect(() => {
146→    if (searchText.length === 0) {
147→      hasTrackedSearchPress.current = false;
148→    }
149→  }, [searchText]);
150→
151→  const getPointsAvailable = useMemo(() => {
152→    return pointsBalance.points ?? 0;
153→  }, [pointsBalance.points]);
154→
155→  const handleGoBack = useCallback(() => {
156→    params?.navigation?.goBack();
157→  }, [params?.navigation]);
158→
159→  const requestPointsExtract = useCallback(() => {
160→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
161→  }, []);
162→
163→  const handleLoadMore = useCallback(() => {
164→    const currentPage = pointsExtract.extractData?.pagination?.page ?? 1;
165→    const totalPages = pointsExtract.extractData?.pagination?.totalPages ?? 1;
166→    const canLoadMore =
167→      currentPage < totalPages && !pointsExtract.isLoadingMore;
168→
169→    if (canLoadMore) {
170→      getPointsExtract({ page: currentPage + 1 });
171→    }
172→  }, [
173→    pointsExtract.extractData?.pagination,
174→    pointsExtract.isLoadingMore,
175→  ]);
176→
177→  const setTransactionsFilters = useCallback(
178→    (filters: AppliedFilters) => {
179→      pointsExtractActions.setTransactionsFilters(filters);
180→    },
181→    [pointsExtractActions],
182→  );
183→
184→  const clearTransactionsFilters = useCallback(() => {
185→    pointsExtractActions.clearTransactionsFilters();
186→  }, [pointsExtractActions]);
187→
188→  const getTransactionsWithFilters = useCallback(
189→    (transactions: PointsTransaction[]): PointsTransaction[] => {
190→      let filtered = transactions;
191→
192→      if (appliedTransactionsFilters) {
193→        const filtersWithDays: AppliedFilters = {
194→          ...appliedTransactionsFilters,
195→          period:
196→            appliedTransactionsFilters.period !== undefined
197→              ? PERIOD_DAYS_MAP[appliedTransactionsFilters.period]
198→              : undefined,
199→        };
200→        filtered = getFilteredTransactions(filtered, filtersWithDays);
201→      }
202→
203→      return filtered;
204→    },
205→    [appliedTransactionsFilters],
206→  );
207→
208→  const getExtractData = useMemo(() => {
209→    if (!pointsExtract.extractData) return undefined;
210→
211→    const transactions = getTransactionsWithFilters(
212→      pointsExtract.extractData.transactions,
213→    );
214→
215→    return {
216→      ...pointsExtract.extractData,
217→      transactions,
218→    };
219→  }, [
220→    pointsExtract.extractData,
221→    getTransactionsWithFilters,
222→  ]);
223→
224→  const getTransactionsData = useMemo(() => {
225→    if (!getExtractData?.transactions) {
226→      return [];
227→    }
228→
229→    if (debouncedSearchText && debouncedSearchText.trim() !== '') {
230→      return getFilteredTransactionsByText(
231→        getExtractData.transactions,
232→        debouncedSearchText,
233→        false,
234→      );
235→    }
236→
237→    return getExtractData.transactions;
238→  }, [
239→    getExtractData?.transactions,
240→    debouncedSearchText,
241→  ]);
242→
243→  useEffect(() => {
244→    if (!getExtractData) return;
245→
246→    let cancelled = false;
247→    const task = InteractionManager.runAfterInteractions(() => {
248→      if (cancelled) return;
249→      const processed = processPointsExtractData({
250→        transactions: getTransactionsData,
251→        pagination: getExtractData.pagination ?? {
252→          page: 1,
253→          pageSize: 100,
254→          total: 0,
255→          totalPages: 0,
256→        },
257→      });
258→      if (!cancelled) {
259→        setTransactionsData(processed.mappedTransactions);
260→      }
261→    });
262→
263→    return () => {
264→      cancelled = true;
265→      task.cancel();
266→    };
267→  }, [
268→    getExtractData,
269→    getTransactionsData,
270→  ]);
271→
272→  const getActiveFiltersCount = useMemo(() => {
273→    let count = 0;
274→    if (
275→      appliedTransactionsFilters?.period !== undefined &&
276→      appliedTransactionsFilters?.period !== null
277→    ) {
278→      count++;
279→    }
280→    if (appliedTransactionsFilters?.types?.length) count++;
281→    return count > 0 ? count.toString() : undefined;
282→  }, [appliedTransactionsFilters]);
283→
284→  const getTransactionsEmptyMessage = useMemo(() => {
285→    const hasSearchText =
286→      debouncedSearchText && debouncedSearchText.trim() !== '';
287→    const hasActiveFilters =
288→      (appliedTransactionsFilters?.period !== undefined &&
289→        appliedTransactionsFilters?.period !== null) ||
290→      (appliedTransactionsFilters?.types?.length ?? 0) > 0;
291→    return hasSearchText || hasActiveFilters
292→      ? SCREEN_STRINGS.EMPTY_SEARCH_RESULTS
293→      : SCREEN_STRINGS.EMPTY_ALL_LIST;
294→  }, [
295→    debouncedSearchText,
296→    appliedTransactionsFilters,
297→  ]);
298→
299→  const getShouldShowTransactionsList =
300→    isLoadingExtract || transactionsData.length > 0;
301→
302→  const canLoadMore =
303→    pointsExtract.extractData?.pagination &&
304→    pointsExtract.extractData.pagination.page <
305→      pointsExtract.extractData.pagination.totalPages;
306→
307→  useEffect(() => {
308→    canLoadMoreRef.current = !!canLoadMore;
309→  }, [canLoadMore]);
310→
311→  useEffect(() => {
312→    isLoadingMoreRef.current = isLoadingMore;
313→  }, [isLoadingMore]);
314→
315→  const handleSearchChange = useCallback(
316→    (text: string) => {
317→      setSearchText(text);
318→    },
319→    [setSearchText],
320→  );
321→
322→  const handleRefresh = useCallback(() => {
323→    setIsRefreshing(true);
324→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
325→    getPointsBalance();
326→    requestPointsExtract();
327→  }, [
328→    requestPointsExtract,
329→    pointsExtractActions,
330→  ]);
331→
332→  const handleError = useCallback(() => {
333→    requestPointsExtract();
334→  }, [requestPointsExtract]);
335→
336→  const handleScroll = useCallback(
337→    (event: NativeSyntheticEvent<NativeScrollEvent>) => {
338→      const { layoutMeasurement, contentOffset, contentSize } =
339→        event.nativeEvent;
340→      const distanceFromBottom =
341→        contentSize.height - layoutMeasurement.height - contentOffset.y;
342→
343→      if (
344→        distanceFromBottom < SCROLL_THRESHOLD &&
345→        canLoadMoreRef.current &&
346→        !isLoadingMoreRef.current
347→      ) {
348→        handleLoadMore();
349→      }
350→    },
351→    [handleLoadMore],
352→  );
353→
354→  const handleIconInfoPress = useCallback(() => {
355→    eventSelectContent(ANALYTICS_EVENTS.POINTS_INFO);
356→    modalizeRefInfo.current?.open?.();
357→  }, []);
358→
359→  const handleFilterIconPress = useCallback(() => {
360→    eventSelectContent({
361→      content_type: 'cta',
362→      ...ANALYTICS_EVENTS.FILTER,
363→    });
364→    modalizeRefFilters.current?.open?.();
365→  }, []);
366→
367→  const handleApplyFilters = useCallback(
368→    (filters: Record<number, unknown>) => {
369→      const period = filters[0] as number | undefined;
370→      const types = filters[1] as string | undefined;
371→
372→      const hasPeriod = period !== undefined && period !== null;
373→      const hasTypes = types !== undefined && types !== null;
374→
375→      if (!hasPeriod && !hasTypes) {
376→        clearTransactionsFilters();
377→      } else {
378→        setTransactionsFilters({
379→          period: hasPeriod ? period : undefined,
380→          types: hasTypes ? [types] : undefined,
381→        });
382→      }
383→    },
384→    [
385→      setTransactionsFilters,
386→      clearTransactionsFilters,
387→    ],
388→  );
389→
390→  const handleTabChange = useCallback((index: number) => {
391→    if (index === 0) {
392→      eventSelectContent({
393→        content_type: 'cta',
394→        content_id: 'aba_todos',
395→        location_1: 'monetizacao',
396→        location_2: 'hub_recompensas_spmais',
397→        location_3: 'extrato_hub_recompensas',
398→      });
399→    } else {
400→      eventSelectContent({
401→        content_type: 'cta',
402→        content_id: 'aba_expirados',
403→        location_1: 'monetizacao',
404→        location_2: 'hub_recompensas_spmais',
405→        location_3: 'extrato_hub_recompensas',
406→      });
407→    }
408→  }, []);
409→
410→  const handleSearchPressIn = useCallback(() => {
411→    if (!hasTrackedSearchPress.current) {
412→      eventSelectContent(ANALYTICS_EVENTS.SEARCH);
413→      hasTrackedSearchPress.current = true;
414→    }
415→  }, []);
416→
417→  const getFilterGroups: FilterGroup[] = useMemo(() => {
418→    return [
419→      {
420→        label: 'Períodos',
421→        options: [
422→          {
423→            label: '7 dias',
424→            value: 0,
425→          },
426→          {
427→            label: '15 dias',
428→            value: 1,
429→          },
430→          {
431→            label: '30 dias',
432→            value: 2,
433→          },
434→          {
435→            label: '60 dias',
436→            value: 3,
437→          },
438→          {
439→            label: '90 dias',
440→            value: 4,
441→          },
442→        ],
443→      },
444→      {
445→        label: 'Tipos de lançamentos',
446→        options: [
447→          {
448→            label: 'Ganhos',
449→            value: 'CREDIT',
450→          },
451→          {
452→            label: 'Usados',
453→            value: 'RESCUE',
454→          },
455→          {
456→            label: 'Expirados',
457→            value: 'EXPIRED',
458→          },
459→        ],
460→      },
461→    ];
462→  }, []);
463→
464→  const getInitialFilters = useMemo(() => {
465→    const filters: Record<number, unknown> = {};
466→    if (
467→      appliedTransactionsFilters?.period !== undefined &&
468→      appliedTransactionsFilters?.period !== null
469→    ) {
470→      filters[0] = appliedTransactionsFilters.period;
471→    }
472→    if (appliedTransactionsFilters?.types?.length) {
473→      filters[1] = appliedTransactionsFilters.types[0];
474→    }
475→    return filters;
476→  }, [appliedTransactionsFilters]);
477→
478→  return {
479→    pointsAvailable: getPointsAvailable,
480→    extractData: getExtractData,
481→    pagination: pointsExtract.extractData?.pagination,
482→    isLoadingExtract,
483→    isLoadingMore,
484→    isLoadingBalance,
485→    hasError,
486→    appliedTransactionsFilters,
487→    isRefreshing,
488→    transactionsData,
489→    searchText,
490→    activeFiltersCount: getActiveFiltersCount,
491→    transactionsEmptyMessage: getTransactionsEmptyMessage,
492→    shouldShowTransactionsList: getShouldShowTransactionsList,
493→    filterGroups: getFilterGroups,
494→    initialFilters: getInitialFilters,
495→    modalizeRefInfo,
496→    modalizeRefFilters,
497→    handleGoBack,
498→    requestPointsExtract,
499→    handleLoadMore,
500→    setTransactionsFilters,
501→    clearTransactionsFilters,
502→    handleSearchChange,
503→    handleRefresh,
504→    handleError,
505→    handleScroll,
506→    handleIconInfoPress,
507→    handleFilterIconPress,
508→    handleApplyFilters,
509→    handleTabChange,
510→    handleSearchPressIn,
511→  };
512→}
513→
514→export { getPlaceholder } from './utils';
515→export { default } from './view';
516→

  1→import {
  2→  Box,
  3→  CardPoints,
  4→  Icon,
  5→  ListCardTransition,
  6→  LoadingFooter,
  7→  SearchUsed,
  8→  SeparatorHorizontal,
  9→  Tabs,
 10→  Text,
 11→} from '@semparar/design-system-app';
 12→import theme from '@semparar/design-system-app/src/styles/theme';
 13→import React, { FC } from 'react';
 14→import { RefreshControl } from 'react-native';
 15→import ApiError from '../../atomic/organisms/ApiError';
 16→import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
 17→import PointsInfoBottomSheet from '../../atomic/organisms/PointsInfoBottomSheet';
 18→import BasicScreen from '../../atomic/templates/BasicScreen';
 19→import { getPlaceholder, useExtractRewardProgramScreen } from './index';
 20→import type {
 21→  EmptyListProps,
 22→  ExtractRewardProgramProps,
 23→  TransactionsListProps,
 24→} from './Models';
 25→
 26→const EmptyList = React.memo<EmptyListProps>(({ label }) => (
 27→  <Box width="100%" justify="center" align="center">
 28→    <Icon
 29→      name="icon-invoice-error"
 30→      size="lg"
 31→      color="INTENSE_COLOR_02"
 32→      mt="meddium"
 33→    />
 34→    <Text
 35→      type="paragraphLG"
 36→      pd="innerGreat"
 37→      color="INTENSE_COLOR_03"
 38→      align="center"
 39→    >
 40→      {label}
 41→    </Text>
 42→  </Box>
 43→));
 44→
 45→EmptyList.displayName = 'EmptyList';
 46→
 47→const TransactionsList = React.memo<TransactionsListProps>(({
 48→  items,
 49→  isLoading,
 50→}) => (
 51→  <ListCardTransition
 52→    items={items}
 53→    isLoading={isLoading}
 54→    scrollEnabled={false}
 55→    mb="meddium"
 56→  />
 57→));
 58→
 59→TransactionsList.displayName = 'TransactionsList';
 60→
 61→const LoadingMore = React.memo(() => (
 62→  <Box width="100%" align="center" justify="center" mt="small" mb="small">
 63→    <LoadingFooter />
 64→  </Box>
 65→));
 66→
 67→LoadingMore.displayName = 'LoadingMore';
 68→
 69→const ExtractRewardProgram: FC<ExtractRewardProgramProps> = ({
 70→  route,
 71→  navigation,
 72→}) => {
 73→  const {
 74→    hasError,
 75→    handleGoBack,
 76→    pointsAvailable,
 77→    isLoadingExtract,
 78→    isLoadingMore,
 79→    isLoadingBalance,
 80→    isRefreshing,
 81→    transactionsData,
 82→    searchText,
 83→    activeFiltersCount,
 84→    transactionsEmptyMessage,
 85→    shouldShowTransactionsList,
 86→    filterGroups,
 87→    initialFilters,
 88→    modalizeRefInfo,
 89→    modalizeRefFilters,
 90→    handleSearchChange,
 91→    handleRefresh,
 92→    handleError,
 93→    handleScroll,
 94→    handleIconInfoPress,
 95→    handleFilterIconPress,
 96→    handleApplyFilters,
 97→    handleTabChange,
 98→    handleSearchPressIn,
 99→  } = useExtractRewardProgramScreen({
100→    route,
101→    navigation,
102→  });
103→
104→  if (hasError) {
105→    return (
106→      <ApiError
107→        title="Algo deu errado!"
108→        subTitle="Por favor, tente de novo."
109→        isLoading={isLoadingExtract}
110→        onPress={handleError}
111→      />
112→    );
113→  }
114→
115→  return (
116→    <>
117→      <BasicScreen
118→        errorButtonOnPress={handleError}
119→        leftIconOnPress={handleGoBack}
120→        title="Extrato"
121→        hasScroll
122→        scrollViewProps={{
123→          refreshControl: (
124→            <RefreshControl
125→              onRefresh={handleRefresh}
126→              refreshing={isRefreshing}
127→              tintColor={theme.colors.BRAND_BASE_01}
128→            />
129→          ),
130→          onScroll: handleScroll,
131→          scrollEventThrottle: 16,
132→        }}
133→      >
134→        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
135→          <CardPoints
136→            icon="icon-benefits"
137→            iconInfo="icon-help"
138→            title="Pontos disponíveis"
139→            valuePoints={
140→              pointsAvailable
141→                ? Math.floor(pointsAvailable).toLocaleString('pt-br')
142→                : '0'
143→            }
144→            hideBottom
145→            isLoading={isLoadingBalance}
146→            onPressIconInfo={handleIconInfoPress}
147→          />
148→
149→          <Text
150→            type="paragraphXXXL"
151→            mb="xxxxs"
152→            mt="xxs"
153→            color="INTENSE_COLOR_05"
154→          >
155→            Lançamentos
156→          </Text>
157→
158→          <SeparatorHorizontal
159→            borderWidth="smaller"
160→            borderColor="BRAND_COMPLEMENT_02"
161→            height={1}
162→            mb="xxxxs"
163→            width="100%"
164→          />
165→          <SearchUsed
166→            placeholder={getPlaceholder()}
167→            onChangeText={handleSearchChange}
168→            value={searchText}
169→            showIcon={!!activeFiltersCount}
170→            firstIcon={undefined}
171→            onPressIn={handleSearchPressIn}
172→            numberIcon={activeFiltersCount}
173→            secondIcon="icon-filter-settings"
174→            secondOnPress={handleFilterIconPress}
175→            showFilter
176→          />
177→        </Box>
178→
179→        <Box
180→          ml={isLoadingExtract ? 'xs' : 'none'}
181→          mr={isLoadingExtract ? 'xs' : 'none'}
182→        >
183→          <Tabs
184→            items={[
185→              {
186→                id: 0,
187→                title: 'Todos',
188→                component: (
189→                  <TransactionsList
190→                    items={transactionsData}
191→                    isLoading={isLoadingExtract}
192→                  />
193→                ),
194→              },
195→              {
196→                id: 1,
197→                title: 'A expirar',
198→                component: <></>,
199→              },
200→            ]}
201→            showBackground={false}
202→            hasScroll={false}
203→            loadingType="light"
204→            onChange={handleTabChange}
205→            type="options"
206→            isLoading={isLoadingExtract}
207→          />
208→          {!shouldShowTransactionsList && (
209→            <EmptyList label={transactionsEmptyMessage} />
210→          )}
211→          {isLoadingMore && <LoadingMore />}
212→        </Box>
213→      </BasicScreen>
214→      <PointsInfoBottomSheet modalizeRef={modalizeRefInfo} />
215→      {filterGroups.length > 0 && (
216→        <FiltersBottomSheet
217→          modalizeRef={modalizeRefFilters}
218→          filterGroups={filterGroups}
219→          onApplyFilters={handleApplyFilters}
220→          initialFilters={initialFilters}
221→        />
222→      )}
223→    </>
224→  );
225→};
226→
227→export default ExtractRewardProgram;
