 1→import React, { useState, useCallback } from 'react';
 2→import { InputBox } from '@semparar/design-system-app';
 3→import type { SDUIComponentProps, SDUIContext, SDUIValidation } from '../models';
 4→import { validateField } from '../utils/validation';
 5→
 6→interface PointsInputProps extends SDUIComponentProps {
 7→  label: string;
 8→  placeholder?: string;
 9→  keyboardType?: string;
10→  textRight?: string;
11→  textError?: string;
12→  mb?: string;
13→  contextKey?: string;
14→  validation?: SDUIValidation;
15→}
16→
17→function buildValidationContext(
18→  context: SDUIContext,
19→  contextKey: string | undefined,
20→  value: string,
21→): SDUIContext {
22→  if (!contextKey) return context;
23→
24→  const segments = contextKey.split('.');
25→  if (segments.length === 1) {
26→    return { ...context, [segments[0]]: parseFloat(value) || 0 };
27→  }
28→
29→  const [root, ...rest] = segments;
30→  const parent = (context[root] ?? {}) as SDUIContext;
31→  let nested: SDUIContext = { ...parent };
32→  let ref = nested;
33→  for (let i = 0; i < rest.length - 1; i++) {
34→    const child = { ...((ref[rest[i]] ?? {}) as SDUIContext) };
35→    ref[rest[i]] = child;
36→    ref = child;
37→  }
38→  ref[rest[rest.length - 1]] = parseFloat(value) || 0;
39→
40→  return { ...context, [root]: nested };
41→}
42→
43→export default function PointsInputAdapter({
44→  props,
45→  context,
46→}: {
47→  props: PointsInputProps;
48→  context: SDUIContext;
49→}) {
50→  const {
51→    label,
52→    placeholder = '0',
53→    keyboardType = 'number-pad',
54→    textRight,
55→    textError,
56→    mb,
57→    contextKey,
58→    validation,
59→  } = props;
60→
61→  const [value, setValue] = useState('');
62→  const [validationError, setValidationError] = useState<string | null>(null);
63→
64→  const handleChange = useCallback(
65→    (text: string) => {
66→      setValue(text);
67→      if (!validation) return;
68→      const ctx = buildValidationContext(context, contextKey, text);
69→      setValidationError(text.length > 0 ? validateField(validation, ctx) : null);
70→    },
71→    [validation, context, contextKey],
72→  );
73→
74→  const handleUseAll = useCallback(() => {
75→    // In a real implementation, this would read from context/store
76→  }, []);
77→
78→  const displayError = validationError ?? (textError ? String(textError) : undefined);
79→
80→  return (
81→    <InputBox
82→      label={String(label)}
83→      placeholder={String(placeholder)}
84→      showLabel
85→      keyboardType={keyboardType}
86→      value={value}
87→      onChangeText={handleChange}
88→      error={!!validationError}
89→      textError={displayError}
90→      textRight={textRight ? String(textRight) : undefined}
91→      onPressTextRight={textRight ? handleUseAll : undefined}
92→      mb={mb}
93→    />
94→  );
95→}
