 1→import React from 'react';
 2→import { Text, Icon } from '@semparar/design-system-app';
 3→import type {
 4→  SDUIComponentProps,
 5→  SDUIContext,
 6→  SDUIRichTextChild,
 7→} from '../models';
 8→
 9→interface RichTextProps extends SDUIComponentProps {
10→  children: SDUIRichTextChild[];
11→  mt?: string;
12→  mb?: string;
13→  align?: string;
14→}
15→
16→function renderNode(node: SDUIRichTextChild, index: number) {
17→  switch (node.type) {
18→    case 'text': {
19→      const style: Record<string, string> = {};
20→      if (node.bold) style.fontWeight = 'bold';
21→      if (node.italic) style.fontStyle = 'italic';
22→      return (
23→        <Text
24→          key={index}
25→          type="bodyMD"
26→          color={node.color}
27→          style={Object.keys(style).length > 0 ? style : undefined}
28→        >
29→          {node.value}
30→        </Text>
31→      );
32→    }
33→    case 'link':
34→      return (
35→        <Text
36→          key={index}
37→          type="bodyMD"
38→          color="PRYMARY_BASE_02"
39→          underline
40→          onPress={() => {}}
41→        >
42→          {node.text}
43→        </Text>
44→      );
45→    case 'icon':
46→      return (
47→        <Icon
48→          key={index}
49→          name={node.name}
50→          color={node.color}
51→          size={node.size ? String(node.size) : 'sm'}
52→        />
53→      );
54→    case 'br':
55→      return '\n';
56→    default:
57→      return null;
58→  }
59→}
60→
61→export default function RichTextAdapter({
62→  props,
63→}: {
64→  props: RichTextProps;
65→  context: SDUIContext;
66→}) {
67→  const { children, mt, mb, align } = props;
68→
69→  if (!Array.isArray(children) || children.length === 0) {
70→    return null;
71→  }
72→
73→  return (
74→    <Text type="bodyMD" mt={mt} mb={mb} align={align}>
75→      {children.map(renderNode)}
76→    </Text>
77→  );
78→}
