 1→import type { SDUIContext, SDUIValidation } from '../models';
 2→import { evaluateRule } from './jsonLogic';
 3→
 4→export function validateField(
 5→  validation: SDUIValidation,
 6→  context: SDUIContext,
 7→): string | null {
 8→  if (!validation?.rules || !Array.isArray(validation.rules)) return null;
 9→
10→  for (const entry of validation.rules) {
11→    if (!entry?.rule || !entry?.message) continue;
12→    const passes = evaluateRule(entry.rule, context);
13→    if (!passes) return entry.message;
14→  }
15→
16→  return null;
17→}
