201→export function processPointsExtractData(
202→  extractData: PointsExtractData | null | undefined,
203→): ProcessedExtractData {
204→  if (!extractData || typeof extractData !== 'object') {
205→    return DEFAULT_PROCESSED_EXTRACT_DATA;
206→  }
207→
208→  try {
209→    const transactions = extractData.transactions || [];
210→    const groupedTransactions = getGroupedTransactionsByDate(transactions);
211→    const mappedTransactions =
212→      PointsDataGroupedByDayMapper.getMappedData(groupedTransactions);
213→
214→    return {
215→      groupedTransactions,
216→      mappedTransactions,
217→    };
218→  } catch (error) {
219→    console.warn('Erro ao processar dados do extrato:', error);
220→    return DEFAULT_PROCESSED_EXTRACT_DATA;
221→  }
222→}
223→
224→export function getPointsExtractFromResponse(
225→  response: Awaited<ReturnType<typeof getPointsExtractApi>>,
226→): PointsExtractData | null {
227→  const apiResponse = response?.data;
228→
229→  if (!apiResponse) {
230→    return null;
231→  }
232→
233→  const transactionsContainer = apiResponse.data ?? apiResponse;
234→  const transactionsDto = transactionsContainer?.transactions;
235→  const pagination =
236→    apiResponse.pagination ?? (apiResponse as any).data?.pagination;
237→
238→  if (!transactionsDto || !Array.isArray(transactionsDto)) {
239→    return null;
240→  }
241→
242→  if (!pagination) {
243→    return null;
244→  }
245→
246→  const transactions = transactionsDto.map(getTransactionFromDto);
247→
248→  return {
249→    transactions,
250→    pagination,
251→  };
252→}
